import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useMusic } from '../../context/MusicContext';
import { Trophy, Heart, Headphones, Flame, Loader2 } from 'lucide-react';

const Ranking = () => {
  const [topSongs, setTopSongs] = useState([]);
  const [loading, setLoading] = useState(true);

  // Lấy dữ liệu từ Context
  const { favorites = [], toggleLikeGlobal } = useMusic();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  // 1. Hàm lấy dữ liệu từ Server
  const fetchRanking = useCallback(async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs/ranking');
      console.log("Dữ liệu Ranking nhận được:", res.data);
      setTopSongs(res.data);
    } catch (err) {
      console.error("Lỗi tải bảng xếp hạng:", err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchRanking();
  }, [fetchRanking]);

  // 2. Hàm xử lý Like và Cập nhật số lượng tại chỗ
  const handleLikeAction = async (songId) => {
    if (!loggedInUser) {
      alert("Vui lòng đăng nhập để bình chọn!");
      return;
    }

    const userId = (loggedInUser._id || loggedInUser.id).toString();
    
    // Kiểm tra xem bài hát này hiện tại user đã like chưa (dựa vào context favorites)
    const isCurrentlyLiked = favorites.some(id => id.toString() === songId.toString());

    console.log(`Bài hát ${songId}: ${isCurrentlyLiked ? "Đang thích -> Bỏ thích" : "Chưa thích -> Thích"}`);

    // Gửi yêu cầu lên server qua Context
    await toggleLikeGlobal(songId);

    // CẬP NHẬT TRẠNG THÁI GIAO DIỆN NGAY LẬP TỨC (Optimistic Update)
    setTopSongs((prevSongs) =>
      prevSongs.map((song) => {
        if (song._id.toString() === songId.toString()) {
          // Tạo bản sao mảng likes hiện tại của bài hát
          let newLikes = song.likes ? [...song.likes] : [];

          if (isCurrentlyLiked) {
            // Nếu đang thích thì giờ xóa userId ra khỏi mảng để giảm số lượng
            newLikes = newLikes.filter((id) => id.toString() !== userId);
          } else {
            // Nếu chưa thích thì thêm userId vào mảng để tăng số lượng
            newLikes.push(userId);
          }

          console.log(`Cập nhật số lượt like mới cho ${song.title}:`, newLikes.length);
          return { ...song, likes: newLikes };
        }
        return song;
      })
    );
  };

  if (loading) {
    return (
      <div style={loadingContainer}>
        <Loader2 size={40} className="animate-spin" color="#1db954" />
        <p>Đang tải bảng xếp hạng...</p>
      </div>
    );
  }

  return (
    <div style={rankPage}>
      <header style={rankHeader}>
        <div style={trophyContainer}>
          <Trophy size={70} color="#FFD700" />
          <Flame size={40} color="#ff4d4d" style={flameIcon} />
        </div>
        <h1 style={titleStyle}>BẢNG XẾP HẠNG IAMNHAC</h1>
        <p style={subtitleStyle}>Top 10 bài hát được yêu thích nhất thời điểm hiện tại</p>
      </header>

      <div style={rankList}>
        {topSongs.length > 0 ? (
          topSongs.map((song, index) => {
            // Kiểm tra trạng thái trái tim
            const isLiked = favorites.some(id => id.toString() === song._id.toString());

            return (
              <div key={song._id} style={rankItem(index)}>
                {/* Thứ hạng */}
                <div style={rankNumber(index)}>{index + 1}</div>

                {/* Ảnh */}
                <img 
                  src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/55'} 
                  style={rankImg} 
                  alt="" 
                />

                {/* Thông tin bài hát */}
                <div style={{ flex: 1 }}>
                  <div style={songName}>{song.title}</div>
                  <div style={songArt}>{song.artist}</div>
                </div>

                {/* Thống kê */}
                <div style={statsContainer}>
                  {/* Lượt nghe */}
                  <div style={statItem}>
                    <Headphones size={18} color="#1db954" />
                    <span style={statValue}>{song.playCount || 0}</span>
                  </div>

                  {/* Lượt thích - Khu vực nhảy số */}
                  <div 
                    style={{ ...statItem, cursor: 'pointer', minWidth: '70px', justifyContent: 'flex-end' }} 
                    onClick={() => handleLikeAction(song._id)}
                  >
                    <Heart 
                      size={22} 
                      fill={isLiked ? "#ff4d4d" : "none"} 
                      color={isLiked ? "#ff4d4d" : "#b3b3b3"} 
                      style={{ transition: 'all 0.3s ease' }}
                    />
                    <span style={{ 
                      color: isLiked ? "#ff4d4d" : "#fff", 
                      fontWeight: '800',
                      fontSize: '18px',
                      marginLeft: '5px'
                    }}>
                      {song.likes ? song.likes.length : 0}
                    </span>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div style={{ padding: '40px', textAlign: 'center', color: '#b3b3b3' }}>
            Chưa có dữ liệu bài hát nào.
          </div>
        )}
      </div>
    </div>
  );
};

/* --- CSS TRONG JS --- */
const rankPage = { padding: '50px 20px', maxWidth: '1000px', margin: '0 auto', color: '#fff', paddingBottom: '150px' };
const rankHeader = { textAlign: 'center', marginBottom: '50px' };
const trophyContainer = { position: 'relative', display: 'inline-block', marginBottom: '15px' };
const flameIcon = { position: 'absolute', bottom: -5, right: -15 };
const titleStyle = { fontSize: '40px', fontWeight: '900', margin: '0', color: '#1db954', letterSpacing: '1px' };
const subtitleStyle = { color: '#b3b3b3', fontSize: '18px', marginTop: '10px' };

const rankList = { background: '#121212', borderRadius: '12px', overflow: 'hidden', border: '1px solid #282828' };
const rankItem = (i) => ({
  display: 'flex', alignItems: 'center', padding: '20px 30px', borderBottom: '1px solid #282828',
  background: i === 0 ? 'linear-gradient(90deg, rgba(255,215,0,0.05) 0%, transparent 100%)' : 'transparent',
});

const rankNumber = (i) => ({
  fontSize: '24px', fontWeight: '900', width: '50px',
  color: i === 0 ? '#FFD700' : i === 1 ? '#C0C0C0' : i === 2 ? '#CD7F32' : '#555'
});

const rankImg = { width: '60px', height: '60px', borderRadius: '8px', marginRight: '20px', objectFit: 'cover' };
const songName = { fontSize: '18px', fontWeight: 'bold', marginBottom: '5px' };
const songArt = { fontSize: '15px', color: '#b3b3b3' };

const statsContainer = { display: 'flex', gap: '35px', alignItems: 'center' };
const statItem = { display: 'flex', alignItems: 'center', gap: '8px' };
const statValue = { fontSize: '16px', fontWeight: '600', color: '#b3b3b3' };
const loadingContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '80vh', color: '#fff', gap: '20px' };

export default Ranking;
